INSERT INTO t_p83689144_profix_network_admin.site_content (key, value) VALUES
('partner.datamobile.main_products', '[{"id":"standart","name":"DataMobile Стандарт","price":"от 936 ₽","badge":null,"description":"Начальная версия для терминалов сбора данных и мобильных устройств. Автоматизирует учёт товаров на складе, в магазине и организациях разного профиля.","features":["Приём и отгрузка товаров","Инвентаризация","Перемещение","Поддержка ТСД на Android"]},{"id":"standart_pro","name":"DataMobile Стандарт Pro","price":"от 1 716 ₽","badge":"Популярный","description":"Расширяет функционал Стандарта: работа по заданию, загрузка шаблонов этикеток и печать на мобильном принтере.","features":["Всё из Стандарта","Работа по заданию","Печать этикеток","Модули: Маркировка, RFID"]},{"id":"online_lite","name":"DataMobile Online Lite","price":"2 496 ₽","badge":null,"description":"Работа в режиме реального времени с защитой от потери связи. Широкие возможности для работы на складе и в торговом зале.","features":["Онлайн-режим","Защита от потери связи","Модули: Маркировка, RFID","Работа в торговом зале"]},{"id":"online","name":"DataMobile Online","price":"от 3 120 ₽","badge":"Максимум","description":"Полноценный онлайн-режим, генерация новых штрихкодов на ТСД, отображение картинок из товароучётной системы.","features":["Полный онлайн-режим","Генерация штрихкодов","Картинки товаров из 1С","Все складские операции"]}]'),
('partner.datamobile.modules', '[{"name":"Модуль Маркировка","price":"от 1 500 ₽","description":"Готовое решение для работы с товарами обязательной маркировки (Честный Знак, ЕГАИС): табак, алкоголь, обувь, одежда, лекарства."},{"name":"Модуль RFID","price":"от 4 500 ₽","description":"Автоматизация учёта по радиочастотным меткам. ТСД с RFID-считывателем распознаёт сотни меток за секунду."}]'),
('partner.datamobile.solutions', '[{"name":"DM.Доставка Pro","price":"от 1 560 ₽/год","icon":"Truck","description":"Мобильное приложение для автоматизации курьерских служб."},{"name":"DM.Invent","price":"от 2 700 ₽","icon":"ClipboardList","description":"Инвентаризация основных средств на ТСД и мобильных устройствах Android."},{"name":"DM.ТОИР","price":"от 2 925 ₽","icon":"Wrench","description":"Обслуживание основных средств: фиксация дефектов, управление ремонтами."},{"name":"DM.Прайсчекер","price":"от 2 100 ₽","icon":"ScanBarcode","description":"ПО для информационных киосков и прайс-чекеров."}]')
